import json
import pandas as pd

# Get company info and symbols
company_info = locals()['var_functions.query_db:2']
if isinstance(company_info, str):
    with open(company_info, 'r') as f:
        company_info = json.load(f)

# Create a mapping of symbol to company description
company_map = {row['Symbol']: row['Company Description'] for row in company_info}

# Get the list of tables from stocktrade database
all_tables_result = locals()['var_functions.list_db:0']
if isinstance(all_tables_result, str):
    with open(all_tables_result, 'r') as f:
        all_tables = json.load(f)
else:
    all_tables = all_tables_result

# Check which symbols have 2008 data and calculate averages
results = []

for company in company_info:
    symbol = company['Symbol']

    # Skip if table doesn't exist
    if symbol not in all_tables:
        continue

    # Try to get 2008 volume data
    try:
        query_db_result = locals().get(f'var_functions.query_db:stocktrade_{symbol}', None)
        if query_db_result is None:
            # Need to query for this symbol
            continue

        if isinstance(query_db_result, str):
            with open(query_db_result, 'r') as f:
                volume_data = json.load(f)
        else:
            volume_data = query_db_result

        if volume_data and len(volume_data) > 0:
            # Extract volumes and calculate average
            volumes = []
            for row in volume_data:
                vol = row.get('Volume')
                if vol is not None:
                    try:
                        # Volume might be string, float, or other format
                        v = float(vol)
                        if v > 0:  # Only positive volumes
                            volumes.append(v)
                    except (ValueError, TypeError):
                        pass

            if volumes:
                avg_volume = sum(volumes) / len(volumes)
                results.append({
                    'symbol': symbol,
                    'company_name': company_map.get(symbol, 'N/A'),
                    'avg_daily_volume_2008': avg_volume,
                    'trading_days': len(volumes)
                })
    except Exception:
        pass

print('__RESULT__:')
print(json.dumps(results))

