                    data = json.load(f)
                    if data and len(data) > 0 and 'avg_volume' in str(data):
                        available_results[key] = data
            except:
                pass
        else:
            if result and len(result) > 0 and 'avg_volume' in str(result):
                available_results[key] = result

# Also check for specific symbol queries already made
symbol_results = {}
